import{_ as n,o as a,c as p,ak as e}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"OSI 七层模型与 TCP/IP 四层模型","description":"","frontmatter":{},"headers":[],"relativePath":"cs/network/osi-tcpip.md","filePath":"cs/network/osi-tcpip.md","lastUpdated":1774353797000}'),l={name:"cs/network/osi-tcpip.md"};function i(r,s,t,c,b,d){return a(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="osi-七层模型与-tcp-ip-四层模型" tabindex="-1">OSI 七层模型与 TCP/IP 四层模型 <a class="header-anchor" href="#osi-七层模型与-tcp-ip-四层模型" aria-label="Permalink to “OSI 七层模型与 TCP/IP 四层模型”">​</a></h1><p>想象一下，你在北京的咖啡馆里，打开手机，给在上海的朋友发了一条微信消息。这条消息是怎么跨越 1200 公里到达对方手机的？</p><p>这不是魔法，而是一套精密的分层协议在起作用。</p><h2 id="为什么需要分层" tabindex="-1">为什么需要分层？ <a class="header-anchor" href="#为什么需要分层" aria-label="Permalink to “为什么需要分层？”">​</a></h2><p>在回答「为什么」之前，先想一个反例：如果所有功能都堆在一个巨大的程序里，会发生什么？</p><ul><li>每次换网卡，都要重写消息发送逻辑</li><li>每次换应用（比如从 QQ 换成微信），都要重新实现网络传输</li><li>出了 bug，根本不知道问题出在哪</li></ul><p>分层解决的就是这个问题：<strong>每一层只关心自己的职责，层与层之间通过标准接口通信</strong>。</p><p>就像邮政系统：你只管写信（应用层），装进信封（传输层），投进邮筒（网络层），剩下的由邮局统一处理。你不需要知道信件是坐飞机还是坐火车运到目的地的。</p><h2 id="osi-七层模型" tabindex="-1">OSI 七层模型 <a class="header-anchor" href="#osi-七层模型" aria-label="Permalink to “OSI 七层模型”">​</a></h2><p>OSI（Open Systems Interconnection Reference Model）是国际标准化组织在 1984 年提出的参考模型，是理解网络通信的理论框架。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        应用层 (Application)                │</span></span>
<span class="line"><span>│  为用户提供网络服务：HTTP、FTP、SMTP、DNS                      │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        表示层 (Presentation)                │</span></span>
<span class="line"><span>│  数据格式转换：加密/解密、压缩/解压、编码/解码                   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        会话层 (Session)                     │</span></span>
<span class="line"><span>│  管理通信会话：建立、维护、终止会话                             │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        传输层 (Transport)                   │</span></span>
<span class="line"><span>│  端到端通信：TCP、UDP、端口号、流量控制                        │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        网络层 (Network)                     │</span></span>
<span class="line"><span>│  路由与寻址：IP、路由器、三层交换机                           │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                     数据链路层 (Data Link)                  │</span></span>
<span class="line"><span>│  帧的传输：MAC 地址、交换机、以太网、ARP                       │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        物理层 (Physical)                    │</span></span>
<span class="line"><span>│  比特流传输：电信号、光信号、网线、光纤、集线器                  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h3 id="各层职责详解" tabindex="-1">各层职责详解 <a class="header-anchor" href="#各层职责详解" aria-label="Permalink to “各层职责详解”">​</a></h3><p><strong>物理层</strong>：把比特流转换为物理信号（电/光/无线电），负责网线、光纤、网卡等硬件。</p><p><strong>数据链路层</strong>：把比特组装成「帧」，通过 MAC 地址在局域网内寻址。典型设备是交换机。</p><p><strong>网络层</strong>：在全局范围内进行路由选择，通过 IP 地址找到目标网络。典型设备是路由器。</p><p><strong>传输层</strong>：建立端到端的连接，确保数据可靠传输。关心的是「这台电脑的某个程序」到「另一台电脑的某个程序」。</p><p><strong>会话层</strong>：管理通信双方的会话状态，比如断点续传、对话控制。</p><p><strong>表示层</strong>：处理数据的「格式」问题，比如 JPEG、ASCII、加密等。</p><p><strong>应用层</strong>：直接面向用户，提供 HTTP、FTP、SMTP、DNS 等具体服务。</p><h2 id="tcp-ip-四层模型" tabindex="-1">TCP/IP 四层模型 <a class="header-anchor" href="#tcp-ip-四层模型" aria-label="Permalink to “TCP/IP 四层模型”">​</a></h2><p>OSI 是理论模型，实际使用的是 TCP/IP 四层模型（有时也叫五层，因为有人把网络接口层拆成了两层）。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        应用层                                │</span></span>
<span class="line"><span>│  HTTP、FTP、SMTP、DNS、Telnet、SSH                          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        传输层                                │</span></span>
<span class="line"><span>│  TCP、UDP                                                    │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        网络层                                │</span></span>
<span class="line"><span>│  IP、ICMP、OSPF、BGP                                         │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                     网络接口层（网络访问层）                   │</span></span>
<span class="line"><span>│  Ethernet、ARP、RARP、PPP                                    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>TCP/IP 四层模型和 OSI 七层模型的对应关系如下：</p><table tabindex="0"><thead><tr><th>OSI 七层</th><th>TCP/IP 四层</th></tr></thead><tbody><tr><td>应用层、表示层、会话层</td><td>应用层</td></tr><tr><td>传输层</td><td>传输层</td></tr><tr><td>网络层</td><td>网络层</td></tr><tr><td>数据链路层、物理层</td><td>网络接口层</td></tr></tbody></table><h2 id="数据封装与分用" tabindex="-1">数据封装与分用 <a class="header-anchor" href="#数据封装与分用" aria-label="Permalink to “数据封装与分用”">​</a></h2><p>理解了分层，接下来看数据是怎么「穿层」的。</p><p>当你发送一个 HTTP 请求时，数据经过每一层都会「加壳」，就像俄罗斯套娃：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>应用层：        [HTTP 请求头 + Body]          ← 你要发送的数据</span></span>
<span class="line"><span>传输层：        [TCP 头 | HTTP 请求头 + Body]   ← 加上源/目的端口</span></span>
<span class="line"><span>网络层：        [IP 头 | TCP 头 | HTTP 请求头 + Body]  ← 加上源/目的 IP</span></span>
<span class="line"><span>数据链路层：    [Ethernet 头 | IP 头 | TCP 头 | HTTP 请求头 + Body | CRC]  ← 加上 MAC 地址</span></span>
<span class="line"><span>物理层：        转换为 010101... 的电信号/光信号</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>接收端则反过来，从物理层逐层「拆壳」，这就是「分用」。</p><p>每一层只处理自己的头部，根据头部中的字段决定把数据交给上一层。这个过程是自动的，对用户透明。</p><h2 id="为什么-osi-模型没有流行" tabindex="-1">为什么 OSI 模型没有流行？ <a class="header-anchor" href="#为什么-osi-模型没有流行" aria-label="Permalink to “为什么 OSI 模型没有流行？”">​</a></h2><p>OSI 模型设计得漂亮、完整，但最终是 TCP/IP 成了事实标准。原因很现实：</p><ol><li><strong>TCP/IP 先入为主</strong>：ARPANET 从 1969 年就开始用了，等 OSI 模型提出时，TCP/IP 已经在大学和研究机构中广泛部署。</li><li><strong>OSI 实现复杂</strong>：七层模型虽然清晰，但实现起来过于复杂，很多功能重复。</li><li><strong>市场推动</strong>：美国国防部和大型企业力推 TCP/IP，形成了事实标准。</li></ol><p>所以面试时如果问到 OSI 模型，重点回答它的<strong>分层思想</strong>和<strong>各层职责</strong>，这是理解网络的基础。</p><h2 id="各层典型设备与协议" tabindex="-1">各层典型设备与协议 <a class="header-anchor" href="#各层典型设备与协议" aria-label="Permalink to “各层典型设备与协议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>物理层：集线器、中继器、网线、光纤</span></span>
<span class="line"><span>数据链路层：交换机、网桥、网卡、ARP</span></span>
<span class="line"><span>网络层：路由器、三层交换机、IP、ICMP</span></span>
<span class="line"><span>传输层：防火墙、四层负载均衡、TCP、UDP</span></span>
<span class="line"><span>应用层：网关、应用服务器、HTTP、DNS、FTP</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>OSI 模型每一层分别解决什么问题？</li><li>为什么说 TCP/IP 是「事实标准」而不是「法定标准」？</li><li>数据在网络中传输时，封装和分用的过程是怎样的？</li><li>「交换机」和「路由器」分别工作在哪一层？有什么区别？</li></ul>`,38)])])}const u=n(l,[["render",i]]);export{h as __pageData,u as default};
